import time
import json
import base64
from pydantic import BaseModel, Field


ROLE_SCOPES: dict[str, list[str]] = {
    'user': ['read:own', 'write:own'],
    'admin': ['read:own', 'write:own', 'read:all', 'write:all', 'delete:all'],
    'moderator': ['read:own', 'write:own', 'read:all', 'delete:own'],
}


class User(BaseModel):
    id: int
    username: str
    email: str
    hashed_password: str
    roles: list[str] = ['user']
    is_active: bool = True


class TokenData(BaseModel):
    user_id: int
    username: str
    scopes: list[str] = Field(default_factory=list)
    expires_at: float


class AuthManager:
    def __init__(self):
        self._users: dict[int, User] = {}
        self._usernames: dict[str, int] = {}
        self._next_id: int = 1

    def hash_password(self, password: str) -> str:
        return "hashed_" + password

    def verify_password(self, password: str, hashed: str) -> bool:
        return self.hash_password(password) == hashed

    def register(self, username: str, email: str, password: str,
                 roles: list[str] | None = None) -> User:
        if username in self._usernames:
            raise ValueError("Username already exists")
        user = User(
            id=self._next_id,
            username=username,
            email=email,
            hashed_password=self.hash_password(password),
            roles=roles if roles is not None else ['user'],
        )
        self._users[self._next_id] = user
        self._usernames[username] = self._next_id
        self._next_id += 1
        return user

    def authenticate(self, username: str, password: str) -> User | None:
        uid = self._usernames.get(username)
        if uid is None:
            return None
        user = self._users[uid]
        if not user.is_active:
            return None
        if not self.verify_password(password, user.hashed_password):
            return None
        return user

    def get_user(self, user_id: int) -> User | None:
        return self._users.get(user_id)


class TokenService:
    def __init__(self, secret: str, default_expiry: int = 3600):
        self._secret = secret
        self._default_expiry = default_expiry

    def create_access_token(self, user: User, scopes: list[str] | None = None) -> str:
        if scopes is None:
            scope_set: set[str] = set()
            for role in user.roles:
                scope_set.update(ROLE_SCOPES.get(role, []))
            scopes = sorted(scope_set)
        payload = {
            "user_id": user.id,
            "username": user.username,
            "scopes": scopes,
            "expires_at": time.time() + self._default_expiry,
            "secret": self._secret,
        }
        return base64.b64encode(json.dumps(payload).encode()).decode()

    def decode_token(self, token: str) -> TokenData:
        try:
            data = json.loads(base64.b64decode(token).decode())
        except Exception:
            raise ValueError("Invalid token")
        if data.get("secret") != self._secret:
            raise ValueError("Invalid token")
        if time.time() > data.get("expires_at", 0):
            raise ValueError("Token expired")
        try:
            return TokenData(
                user_id=data["user_id"],
                username=data["username"],
                scopes=data.get("scopes", []),
                expires_at=data["expires_at"],
            )
        except Exception:
            raise ValueError("Invalid token")


class Permission:
    @staticmethod
    def require_scope(scope: str, token_data: TokenData) -> bool:
        return scope in token_data.scopes

    @staticmethod
    def require_any_scope(scopes: list[str], token_data: TokenData) -> bool:
        return any(s in token_data.scopes for s in scopes)

    @staticmethod
    def require_all_scopes(scopes: list[str], token_data: TokenData) -> bool:
        return all(s in token_data.scopes for s in scopes)

    @staticmethod
    def check_resource_access(token_data: TokenData, resource_owner_id: int, action: str) -> bool:
        if f"{action}:all" in token_data.scopes:
            return True
        if f"{action}:own" in token_data.scopes and token_data.user_id == resource_owner_id:
            return True
        return False


def build_auth_system(secret: str) -> dict:
    auth = AuthManager()
    tokens = TokenService(secret)
    admin = auth.register("admin", "admin@test.com", "admin123", roles=["admin"])
    user = auth.register("user1", "user1@test.com", "pass123", roles=["user"])
    return {"auth": auth, "tokens": tokens, "admin": admin, "user": user}
